-- TB (Terjemahan Baru) — Indonesian standard translation
INSERT INTO bible_verses (reference, translation, text, category) VALUES
-- LOVE
('1 Korintus 13:4-5',   'TB', 'Kasih itu sabar; kasih itu murah hati; ia tidak cemburu. Ia tidak memegahkan diri dan tidak sombong. Ia tidak melakukan yang tidak sopan dan tidak mencari keuntungan diri sendiri.', 'LOVE'),
('1 Yohanes 4:7',       'TB', 'Saudara-saudaraku yang kekasih, marilah kita saling mengasihi, sebab kasih itu berasal dari Allah; dan setiap orang yang mengasihi, lahir dari Allah dan mengenal Allah.', 'LOVE'),
('Rut 1:16',            'TB', 'Tetapi kata Rut: "Janganlah desak aku meninggalkan engkau dan pulang dengan tidak mengikuti engkau; sebab ke mana engkau pergi, ke situ jugalah aku pergi."', 'LOVE'),
-- COVENANT
('Kejadian 2:24',       'TB', 'Sebab itu seorang laki-laki akan meninggalkan ayahnya dan ibunya dan bersatu dengan isterinya, sehingga keduanya menjadi satu daging.', 'COVENANT'),
('Markus 10:9',         'TB', 'Karena itu, apa yang telah dipersatukan Allah, tidak boleh diceraikan manusia.', 'COVENANT'),
('Maleakhi 2:14',       'TB', 'Tuhan telah menjadi saksi antara engkau dan isteri masa mudamu yang kepadanya engkau telah tidak setia, padahal dialah teman sekutumu dan isteri perjanjianmu.', 'COVENANT'),
-- BLESSING
('Yeremia 29:11',       'TB', 'Sebab Aku ini mengetahui rancangan-rancangan apa yang ada pada-Ku mengenai kamu, demikianlah firman Tuhan, yaitu rancangan damai sejahtera dan bukan rancangan kecelakaan, untuk memberikan kepadamu hari depan yang penuh harapan.', 'BLESSING'),
('Mazmur 128:3',        'TB', 'Isterimu akan menjadi seperti pohon anggur yang subur di dalam rumahmu; anak-anakmu seperti tunas pohon zaitun sekeliling mejamu.', 'BLESSING'),
('Amsal 18:22',         'TB', 'Siapa mendapat isteri, mendapat sesuatu yang baik, dan ia dikenan Tuhan.', 'BLESSING'),
('Ibrani 13:4',         'TB', 'Hendaklah kamu semua penuh hormat terhadap pernikahan dan janganlah kamu mencemarkan tempat tidur, sebab orang-orang sundal dan pezinah akan dihakimi Allah.', 'BLESSING');

-- BIS (Bahasa Indonesia Sehari-hari) — modern colloquial Indonesian
INSERT INTO bible_verses (reference, translation, text, category) VALUES
-- LOVE
('1 Korintus 13:4-5',   'BIS', 'Orang yang mengasihi itu sabar dan baik hati. Ia tidak iri hati, tidak membanggakan diri, dan tidak sombong. Ia tidak berbuat hal-hal yang memalukan; ia tidak mementingkan dirinya sendiri.', 'LOVE'),
('1 Yohanes 4:7',       'BIS', 'Saudara-saudaraku yang kekasih, marilah kita saling mengasihi, karena kasih berasal dari Allah. Setiap orang yang mengasihi berasal dari Allah dan mengenal Allah.', 'LOVE'),
('Rut 1:16',            'BIS', 'Rut menjawab, "Jangan suruh aku meninggalkan engkau! Di mana engkau pergi, aku pun pergi. Di mana engkau tinggal, aku pun tinggal."', 'LOVE'),
-- COVENANT
('Kejadian 2:24',       'BIS', 'Itulah sebabnya seorang laki-laki meninggalkan ayah dan ibunya, lalu hidup bersama dengan isterinya. Mereka menjadi satu.', 'COVENANT'),
('Markus 10:9',         'BIS', 'Jadi apa yang telah disatukan Allah, janganlah dipisahkan manusia.', 'COVENANT'),
('Maleakhi 2:14',       'BIS', 'TUHAN telah menjadi saksi perkawinanmu ketika engkau mengucapkan janji kepada isteri mudamu. Namun sekarang engkau tidak setia kepadanya, padahal ia adalah teman hidupmu.', 'COVENANT'),
-- BLESSING
('Yeremia 29:11',       'BIS', 'TUHAN berfirman, "Aku mempunyai rencana untuk kebaikanmu, bukan untuk mencelakakan kamu. Aku akan memberikan kepada kamu harapan dan masa depan yang baik."', 'BLESSING'),
('Mazmur 128:3',        'BIS', 'Isterimu akan subur seperti pohon anggur di rumahmu; anak-anakmu seperti tunas zaitun di sekeliling mejamu.', 'BLESSING'),
('Amsal 18:22',         'BIS', 'Siapa mendapat isteri yang baik, mendapat berkat yang besar; ia dikasihi oleh TUHAN.', 'BLESSING'),
('Ibrani 13:4',         'BIS', 'Perkawinan haruslah dihormati oleh semua orang dan jangan ada yang melanggar kesetiaan perkawinan, karena Allah akan menghukum orang-orang yang melanggarnya.', 'BLESSING');
